const square = (n: number): number => n * n;

const isEven = (n: number): boolean => n % 2 === 0;

const sum = (nums: number[]): number => {
  let total: number = 0;
  for (const n of nums) total += n;
  return total;
};

console.log(square(5));           // 25
console.log(isEven(4));           // true
console.log(sum([1, 2, 3, 4]));   // 10

function search(arr: number[], target: number, start: number = 0): number {
  for (let i = start; i < arr.length; i++) {
    if (arr[i] === target) return i;
  }
  return -1;
}

function formatResult(val: number, label?: string): string {
  return label ? `${label}: ${val}` : `${val}`;
}

console.log(search([5, 3, 8, 3], 3));      // 1
console.log(search([5, 3, 8, 3], 3, 2));   // 3
console.log(formatResult(42));              // 42
console.log(formatResult(42, "answer"));    // answer: 42

