function pad(s: string, len: number, fill: string = ___): string {
  let result: string = s
  while (result.length < len) {
    result += fill
  }
  return result
}

console.log(`"${pad("hi", 5)}"`)
console.log(`"${pad("hi", 5, ".")}"`)

